/**
 * gestionEleves.gs
 * Fichier complet prêt à coller.
 */

/** --- Configuration (modifiez si besoin) --- */
const SPREADSHEET_ID = '1WY5Skx-TCgDqdZAsqsI6x21OYz0CAtmR6bOgeMHdYhQ'; // <-- Remplacez par votre ID si nécessaire
const SHEET_NAME = 'GESTION DES ELEVES';
const SCRIPT_TZ = Session.getScriptTimeZone();

/** --- 1) doGet : affiche la page HTML principale --- */
function doGet(e) {
  // Utilisez createTemplateFromFile si vous voulez pouvoir injecter des variables 
  // ou inclure côté serveur (<?!= include('Client') ?> dans votre HTML).
  return HtmlService.createTemplateFromFile('FormulaireEleve.view')
    .evaluate()
    .setTitle('Formulaire d\'inscription');
}

/** --- 2) include : permet d'inclure un fichier HTML côté serveur via <?!= include('Client') ?> --- */
function include(filename) {
  return HtmlService.createHtmlOutputFromFile(filename).getContent();
}

/** --- 3) clean : nettoie une valeur (trim, multiple espaces => 1) --- */
function clean(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim().replace(/\s+/g, ' ');
}

/** --- 4) normalize : normalise pour comparaison (nettoie, minuscules, retire diacritiques) --- */
function normalize(value) {
  var s = clean(value).toLowerCase();
  // Retirer les accents / diacritiques (fonctionne dans V8)
  try {
    s = s.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  } catch (e) {
    // Si normalize non supporté, on garde la version sans changes
  }
  return s;
}

/** --- 5) tolsoDate / toIsoDate : convertit une date (Date ou string) en 'YYYY-MM-DD' --- */
function tolsoDate(value) {
  if (value === null || value === undefined || value === '') return '';
  // Si c'est déjà un objet Date
  if (Object.prototype.toString.call(value) === '[object Date]' || value instanceof Date) {
    if (isNaN(value.getTime())) return '';
    return Utilities.formatDate(value, SCRIPT_TZ, 'yyyy-MM-dd');
  }
  var s = String(value).trim();
  // Si déjà en format ISO yyyy-mm-dd
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  // Tenter parse
  var parsed = new Date(s);
  if (!isNaN(parsed.getTime())) {
    return Utilities.formatDate(parsed, SCRIPT_TZ, 'yyyy-MM-dd');
  }
  // En dernier recours, retourner la chaîne nettoyée
  return s;
}
function toIsoDate(value){ return tolsoDate(value); } // alias

/** --- 6) isValidEmail : validation basique d'email --- */
function isValidEmail(email) {
  if (!email) return false;
  var s = String(email).trim();
  // regex simple, robuste
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(s);
}

/** --- 7) genererCodeEleve : génère un code basé sur option/classe/num --- */
function genererCodeEleve(data, numeroEleve) {
  var classe = clean(data.classe || '');
  var parallele = clean(data.parallele || '');
  var opt = clean(data.option || '');

  // ⚡ Maintenant : prendre exactement les 3 premiers caractères de l'option sélectionnée
  var optCode = opt.substring(0,3).toUpperCase();

  var classeCode = classe.replace(/\s+/g, '').toUpperCase();
  if (parallele) classeCode += parallele.toUpperCase();

  var num = (numeroEleve ? Number(numeroEleve) : 0);
  if (isNaN(num)) num = 0;
  var numCode = String(num).padStart(4, '0');

  return optCode + classeCode + numCode;
}

/** --- 8) saveEleve : point d'entrée appelé côté client via google.script.run.saveEleve(...) --- */
function saveEleve(data) {
  try {
    if (!data) throw new Error('Données manquantes.');

    // Champs obligatoires (côté serveur aussi)
    var required = ['nom','postnom','prenom','sexe','lieuNaissance','dateNaissance',
      'tuteur','telephone','adresse','classe','parallele','option',
      'nomMere','nomPere','email'];
    for (var i=0;i<required.length;i++){
      var k = required[i];
      if (!data[k] || String(data[k]).trim() === '') {
        throw new Error('Champ obligatoire manquant : ' + k);
      }
    }

    // Vérification email si renseigné
    if (data.email && data.email.toString().trim() !== '' && !isValidEmail(data.email)) {
      throw new Error('Adresse e-mail invalide.');
    }

    // Ouvrir feuille
    var ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    var sheet = ss.getSheetByName(SHEET_NAME);
    if (!sheet) throw new Error("Feuille '" + SHEET_NAME + "' introuvable.");

    // Normalisation utilisée pour la détection doublons
    var newNom = normalize(data.nom);
    var newPost = normalize(data.postnom);
    var newPre = normalize(data.prenom);
    var newDateIso = tolsoDate(data.dateNaissance);

    // Verrou pour éviter conditions de course
    var lock = LockService.getScriptLock();
    lock.waitLock(10000); // attendre max 10s
    try {
      var lastRow = sheet.getLastRow();
      var lastColumn = sheet.getLastColumn();

      // Lire les données existantes (à partir de la ligne 2 si la 1 est en-tête)
      var existing = [];
      if (lastRow >= 2 && lastColumn >= 1) {
        existing = sheet.getRange(2, 1, Math.max(0, lastRow-1), lastColumn).getValues();
      }

      // Vérifier doublon : nom + postnom + prenom + dateNaissance
      for (var r=0; r<existing.length; r++) {
        var row = existing[r];
        // Mapping supposé : A=CODE, B=NOM, C=POSTNOM, D=PRENOM, G=DATENAISSANCE (index 6)
        var rowNom = normalize(row[1]);
        var rowPost = normalize(row[2]);
        var rowPre = normalize(row[3]);
        var rowDateIso = tolsoDate(row[6]);

        if (rowNom === newNom && rowPost === newPost && rowPre === newPre && rowDateIso === newDateIso) {
          throw new Error('Un élève avec ces informations existe déjà.');
        }
      }

      // Générer CODE ELEVE
      var numeroPourCode = sheet.getLastRow(); // on garde logique antérieure ; ceci peut être ajusté
      var codeEleve = genererCodeEleve(data, numeroPourCode + 1);

      // Préparer valeur date pour la cellule (Date object si possible)
      var dateNaissanceCell = (function(){
        if (!data.dateNaissance) return '';
        if (/^\d{4}-\d{2}-\d{2}$/.test(String(data.dateNaissance).trim())) {
          var parts = String(data.dateNaissance).split('-');
          return new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
        }
        var d = new Date(data.dateNaissance);
        if (!isNaN(d.getTime())) return d;
        return data.dateNaissance;
      })();

      var dateInscription = Utilities.formatDate(new Date(), SCRIPT_TZ, 'yyyy-MM-dd HH:mm:ss');

      // Construire ligne à ajouter (colonne A.. => adapter si votre feuille diffère)
      var ligne = [
        codeEleve,                      // A CODE
        clean(data.nom),                // B NOM
        clean(data.postnom),            // C POSTNOM
        clean(data.prenom),             // D PRENOM
        clean(data.sexe || ''),         // E SEXE
        clean(data.lieuNaissance || ''),// F LIEU NAISSANCE
        dateNaissanceCell,              // G DATE NAISSANCE (Date obj ou string)
        clean(data.tuteur || ''),       // H TUTEUR
        clean(data.telephone || ''),    // I TELEPHONE
        clean(data.adresse || ''),      // J ADRESSE
        clean(data.classe || ''),       // K CLASSE
        clean(data.parallele || ''),    // L PARALLELE
        clean(data.option || ''),       // M OPTION
        clean(data.annee || '2025-2026'),// N ANNEE SCOLAIRE (par défaut)
        clean(data.nomMere || ''),      // O NOM MERE
        clean(data.nomPere || ''),      // P NOM PERE
        clean(data.email || ''),        // Q EMAIL
        dateInscription                  // R DATE_INSCRIPTION
      ];

      // Append
      sheet.appendRow(ligne);
    } finally {
      try { lock.releaseLock(); } catch (e) { /* ignore */ }
    }

    // Envoi email optionnel (ne doit pas casser l'opération)
    if (data.email && isValidEmail(data.email)) {
      try {
        MailApp.sendEmail({
          to: data.email,
          subject: 'Confirmation d\'inscription',
          htmlBody: '<p>Bonjour ' + escapeHtml(data.prenom) + ' ' + escapeHtml(data.nom) + ',</p>' +
                    '<p>Votre inscription a été enregistrée. Code élève : <b>' + escapeHtml(codeEleve) + '</b></p>'
        });
      } catch (e) {
        Logger.log('Échec envoi mail : ' + e.message);
      }
    }

    return { status: 'OK', code: codeEleve };

  } catch (err) {
    Logger.log('saveEleve erreur: ' + (err && err.message ? err.message : err));
    return { status: 'ERROR', message: (err && err.message) ? err.message : String(err) };
  }
}

/** --- petit helper de sécurité HTML --- */
function escapeHtml(text) {
  if (text === null || text === undefined) return '';
  return String(text)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}
